const results = ($.steps.trendResearch.response && $.steps.trendResearch.response.results) ? $.steps.trendResearch.response.results : [];
let trendData = '';
results.slice(0, 8).forEach((r, i) => {
  trendData += (i + 1) + '. ' + (r.title || r.url) + '\n';
  trendData += '   ' + (r.text || '').slice(0, 200) + '\n\n';
});
return { trendData, trendCount: results.length };

const topic = $.input.topic;
const count = $.input.scriptCount || 3;
const trends = $.steps.compileTrends.output.trendData;

const prompt = `You are an expert viral video content creator and social media strategist. Generate ${count} viral short-form video scripts for the topic: "${topic}".

TRENDING CONTENT RESEARCH:
${trends || 'No trend data available — use your expertise.'}

Each script should follow proven viral formats (storytime, POV, hot take, tutorial, before/after, etc.).

Return ONLY valid JSON with this exact structure:
{
  "topic": "${topic}",
  "scripts": [
    {
      "number": 1,
      "title": "<catchy title for the video>",
      "format": "<viral format type: storytime|POV|hot-take|tutorial|before-after|reaction|list|challenge>",
      "hook": "<first 3 seconds — must stop the scroll>",
      "script": "<full 30-60 second script with [VISUAL DIRECTIONS] inline>",
      "cta": "<call to action at the end>",
      "hashtags": "<8-12 relevant hashtags>",
      "estimatedViews": "<low: <10K|medium: 10K-100K|high: 100K+>",
      "whyItWorks": "<1 sentence explaining the viral mechanics>"
    }
  ],
  "trendInsight": "<2 sentences on current trends in this space>"
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { topic: $.input.topic, scripts: [], trendInsight: raw.slice(0, 500) }; }

const ai = $.steps.parseAI.output;
const scripts = ai.scripts || [];
const now = new Date().toISOString().split('T')[0];

const sheetData = scripts.map(s => ({
  'Date': now,
  'Number': s.number || '',
  'Title': s.title || '',
  'Format': s.format || '',
  'Hook': s.hook || '',
  'Script': (s.script || '').slice(0, 500),
  'CTA': s.cta || '',
  'Hashtags': s.hashtags || '',
  'Est. Views': s.estimatedViews || '',
  'Why It Works': s.whyItWorks || '',
  'Status': 'Draft',
  'Topic': ai.topic || $.input.topic
}));

return { sheetData, scriptCount: scripts.length, trendInsight: ai.trendInsight || '' };

const ai = $.steps.parseAI.output;
const scripts = ai.scripts || [];
const topic = ai.topic || $.input.topic;
const trendInsight = $.steps.prepareSheetData.output.trendInsight;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':fire: Viral Video Scripts: ' + topic, emoji: true } });

if (trendInsight) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Trend Insight:* ' + trendInsight } });
}
blocks.push({ type: 'divider' });

scripts.slice(0, 5).forEach((s, i) => {
  let text = '*' + (s.number || i + 1) + '. ' + (s.title || 'Untitled') + '* (' + (s.format || 'general') + ')\n';
  text += ':hook: *Hook:* ' + (s.hook || '') + '\n';
  text += ':chart_with_upwards_trend: *Est. Views:* ' + (s.estimatedViews || 'unknown') + '\n';
  text += ':bulb: ' + (s.whyItWorks || '') + '\n';
  text += (s.hashtags || '');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
  if (i < scripts.length - 1) blocks.push({ type: 'divider' });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: scripts.length + ' viral scripts generated | Saved to Google Sheets | Powered by Exa + Claude AI' }] });

const fallback = 'Viral Scripts: ' + scripts.length + ' scripts generated for ' + topic;
return { blocks, fallback };
